	@Test
	void valuesObjectBindingEstimatesDerivedObservationEncounterSurface(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadSyntheticMedicalObservations(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();

			BindingSetAssignment values = observationValueBindings();
			StatementPattern value = new StatementPattern(Var.of("obs"), Var.of("valuePredicate", MED_VALUE),
					Var.of("value"));
			StatementPattern hasObservation = new StatementPattern(Var.of("enc"),
					Var.of("hasObservationPredicate", MED_HAS_OBSERVATION), Var.of("obs"));
			JoinOrderPlanner planner = (JoinOrderPlanner) store.getBackingStore().getEvaluationStatistics();
			JoinOrderPlanner.JoinOrderPlan plan = planner
					.estimateJoinOrder(List.of(values, value, hasObservation), Set.of(),
							JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING, List.of())
					.orElseThrow();

			assertEstimatedWorkMatchesStepSum(plan);
			int hasObservationIndex = plan.getOrderedArgs().indexOf(hasObservation);
			assertTrue(hasObservationIndex >= 0, "Expected hasObservation in the selected plan: " + plan);
			JoinOrderPlanner.PlanStep hasObservationStep = plan.getSteps().get(hasObservationIndex);

			double expectedSurfaceRows = 3.0d * OBSERVATIONS_PER_VALUE;
			assertEquals("lmdb-finite-derived-surface", hasObservationStep.getStringMetrics()
					.get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE),
					"The finite value anchor should derive the ?obs surface before costing hasObservation. plan="
							+ plan.getOrderedArgs() + ", metrics=" + hasObservationStep.getStringMetrics()
							+ hasObservationStep.getDoubleMetrics() + ", work="
							+ hasObservationStep.getStepWorkRows());
			assertTrue(hasObservationStep.getDoubleMetrics()
					.get(TelemetryMetricNames.PLANNED_ACCESS_ROWS) <= expectedSurfaceRows * 1.25d,
					"The derived hasObservation lookup should expose access rows near the finite ?obs surface. "
							+ "expected=" + expectedSurfaceRows + ", metrics="
							+ hasObservationStep.getStringMetrics() + hasObservationStep.getDoubleMetrics()
							+ ", work=" + hasObservationStep.getStepWorkRows());
			assertTrue(hasObservationStep.getStepWorkRows() <= expectedSurfaceRows * 2.25d,
					"The derived hasObservation step should stay near access plus emitted rows for the finite "
							+ "?obs surface. expected=" + expectedSurfaceRows + ", metrics="
							+ hasObservationStep.getStringMetrics() + hasObservationStep.getDoubleMetrics()
							+ ", work=" + hasObservationStep.getStepWorkRows());
		} finally {
			repository.shutDown();
		}
	}

	private static void loadSyntheticEngineeringAssemblies(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 1; i <= ASSEMBLY_COUNT; i++) {
				Resource assembly = assembly(i);
				connection.add(assembly, ENG_NAME, VF.createLiteral("Assembly " + i));
				connection.add(assembly, RDF_TYPE, ENG_ASSEMBLY);
				for (int componentIndex = 0; componentIndex < COMPONENTS_PER_ASSEMBLY; componentIndex++) {
					connection.add(VF.createIRI("urn:test:engineering:component:" + i + ":" + componentIndex),
							ENG_PART_OF, assembly);
				}
			}
			for (int i = 0; i < 2_000; i++) {
				Resource assembly = VF.createIRI("urn:test:engineering:noise-assembly:" + i);
				connection.add(assembly, ENG_NAME, VF.createLiteral("Noise Assembly " + i));
				connection.add(assembly, RDF_TYPE, ENG_ASSEMBLY);
			}
			connection.commit();
		}
	}

	private static void loadSyntheticMedicalObservations(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			int[] selectedValues = { 50, 60, 70 };
			for (int value : selectedValues) {
				for (int i = 0; i < OBSERVATIONS_PER_VALUE; i++) {
					Resource observation = VF.createIRI("urn:test:medical:observation:" + value + ":" + i);
					Resource encounter = VF.createIRI("urn:test:medical:encounter:" + value + ":" + i);
					connection.add(observation, MED_VALUE, VF.createLiteral(String.valueOf(value), XSD.INTEGER));
					connection.add(encounter, MED_HAS_OBSERVATION, observation);
				}
			}
			for (int i = 0; i < 2_000; i++) {
				Resource observation = VF.createIRI("urn:test:medical:noise-observation:" + i);
				connection.add(observation, MED_VALUE, VF.createLiteral(String.valueOf(1_000 + i), XSD.INTEGER));
			}
			connection.commit();
		}
	}

	private static Resource assembly(int index) {
		return VF.createIRI("urn:test:engineering:assembly:" + index);
	}

	private static BindingSetAssignment assemblyNameBindings() {
		BindingSetAssignment assignment = new BindingSetAssignment();
		List<BindingSet> bindingSets = new ArrayList<>();
		for (int i = 1; i <= ASSEMBLY_COUNT; i++) {
			QueryBindingSet bindingSet = new QueryBindingSet();
			bindingSet.addBinding("assemblyName", VF.createLiteral("Assembly " + i));
			bindingSets.add(bindingSet);
		}
		assignment.setBindingSets(bindingSets);
		return assignment;
	}

	private static void assertDirectFiniteDerivedPartOfSurface(LmdbStore store, BindingSetAssignment assemblyNames,
			StatementPattern name, StatementPattern type, StatementPattern partOf) {
		JoinFactorCostModel costModel = (JoinFactorCostModel) store.getBackingStore().getEvaluationStatistics();
		Optional<JoinFactorCostModel.FactorCostEstimate> estimate = costModel.estimateFactorCost(partOf,
				JoinFactorCostModel.CostContext.of(Set.of("assemblyName", "assembly"), 3.0d, 3.0d, true, true,
						Map.of("assemblyName", Set.of(VF.createLiteral("Assembly 1"),
								VF.createLiteral("Assembly 2"), VF.createLiteral("Assembly 3"))),
						List.of(assemblyNames, name, type)));
		assertTrue(estimate.isPresent(), "Expected a direct cost-model estimate for the derived partOf surface");
		assertEquals("lmdb-finite-derived-surface",
				estimate.get().getStringMetrics().get(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE),
				"The direct cost-model path should derive the ?assembly surface from finite assembly names. metrics="
						+ estimate.get().getStringMetrics() + estimate.get().getDoubleMetrics());
	}

	private static BindingSetAssignment observationValueBindings() {
		BindingSetAssignment assignment = new BindingSetAssignment();
		List<BindingSet> bindingSets = new ArrayList<>();
		for (int value : new int[] { 50, 60, 70 }) {
			QueryBindingSet bindingSet = new QueryBindingSet();
			bindingSet.addBinding("value", VF.createLiteral(String.valueOf(value), XSD.INTEGER));
			bindingSets.add(bindingSet);
		}
		assignment.setBindingSets(bindingSets);
		return assignment;
	}

	private static void assertEstimatedWorkMatchesStepSum(JoinOrderPlanner.JoinOrderPlan plan) {
		double stepWorkSum = plan.getSteps()
				.stream()
				.mapToDouble(JoinOrderPlanner.PlanStep::getStepWorkRows)
				.sum();
		assertEquals(stepWorkSum, plan.getEstimatedTotalWork(), 1.0e-9,
				"Planner total work should equal sum(stepWorkRows)");
		for (TupleExpr orderedArg : plan.getOrderedArgs()) {
			assertTrue(plan.getSteps().size() == plan.getOrderedArgs().size(),
					"Expected one planner step per factor: " + orderedArg);
		}
	}
